import{_ as t,o as n,c as i,a2 as o}from"./chunks/framework.CvZWOya4.js";const u=JSON.parse('{"title":"Custom Consent Modules","description":"","frontmatter":{},"headers":[],"relativePath":"implementation/custom-consent-modules.md","filePath":"implementation/custom-consent-modules.md","lastUpdated":1784032317000}'),a={name:"implementation/custom-consent-modules.md"};function s(r,e,l,d,c,p){return n(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="custom-consent-modules" tabindex="-1">Custom Consent Modules <a class="header-anchor" href="#custom-consent-modules" aria-label="Permalink to &quot;Custom Consent Modules&quot;">​</a></h1><p>The MII Broad Consent pipeline documented in <a href="./consent.html">Consent Handling</a> is TORCH&#39;s <strong>default</strong> consent implementation, not a fixed part of the core application. Consent handling sits behind a <code>ConsentEvaluator</code> extension point (<a href="https://github.com/medizininformatik-initiative/torch/issues/1068" target="_blank" rel="noreferrer">#1068</a>), so institutions with a different consent model can supply their own implementation — including one that only partially resembles the gate/window/retro-modifier model — <strong>without forking or rebuilding TORCH</strong>.</p><h2 id="how-it-s-packaged" tabindex="-1">How it&#39;s packaged <a class="header-anchor" href="#how-it-s-packaged" aria-label="Permalink to &quot;How it&#39;s packaged&quot;">​</a></h2><p>TORCH&#39;s build is split into three Maven modules:</p><table tabindex="0"><thead><tr><th>Module</th><th>Contains</th></tr></thead><tbody><tr><td><code>torch-consent-api</code></td><td>The <code>ConsentEvaluator</code> interface and its supporting types (<code>ConsentContext</code>, <code>PatientSet</code>, <code>ConsentDataClient</code>). Stable extension surface.</td></tr><tr><td><code>torch-consent-mii</code></td><td>The MII Broad Consent implementation documented in <a href="./consent.html">Consent Handling</a>. Built as its own jar, not compiled into the main application jar.</td></tr><tr><td><code>torch-app</code></td><td>The core application. Depends on <code>torch-consent-mii</code> only for its own tests — the production image never bundles it directly.</td></tr></tbody></table><p>The main application jar is launched with Spring Boot&#39;s <code>PropertiesLauncher</code>, which adds every jar found in a plugins directory (<code>LOADER_PATH</code>, default <code>/app/plugins</code> — see <a href="./../configuration.html">Configuration</a>) to the classpath at startup, on top of the jars already bundled inside it. The Docker image ships the MII jar in that directory as a separate file specifically so it can be swapped out.</p><h2 id="replacing-the-default-implementation" tabindex="-1">Replacing the default implementation <a class="header-anchor" href="#replacing-the-default-implementation" aria-label="Permalink to &quot;Replacing the default implementation&quot;">​</a></h2><ol><li>Implement <code>ConsentEvaluator</code> from <code>torch-consent-api</code> (in any package — it does not need to live under <code>de.medizininformatikinitiative.torch</code>): <ul><li><code>validate(ConsentContext)</code> — runs once when a CRTDL is submitted; reject malformed consent criteria by throwing.</li><li><code>evaluate(ConsentContext, PatientSet)</code> — runs once per patient batch; returns the consent-permitted period per patient, or <code>Optional.empty()</code> if no consent requirement applies to this request.</li></ul></li><li>Register the implementation as a Spring bean via a <code>@AutoConfiguration</code> class listed in your own <code>META-INF/spring/org.springframework.boot.autoconfigure.AutoConfiguration.imports</code> (this is how it&#39;s discovered — plain <code>@Component</code> scanning does not reach classes outside TORCH&#39;s own packages). Guard the bean with <code>@ConditionalOnMissingBean(ConsentEvaluator.class)</code> if you want to keep the MII implementation as a fallback when your jar is absent.</li><li>Build the jar and place it in the plugins directory in place of (or alongside, if using <code>@ConditionalOnMissingBean</code>) <code>torch-consent-mii.jar</code>, then restart the container. No TORCH rebuild is required.</li></ol><p>If the plugins directory ends up empty, TORCH fails to start with <code>NoSuchBeanDefinitionException</code> for <code>ConsentEvaluator</code> — startup without any consent evaluation is intentionally not supported.</p><h2 id="mounting-the-plugins-directory" tabindex="-1">Mounting the plugins directory <a class="header-anchor" href="#mounting-the-plugins-directory" aria-label="Permalink to &quot;Mounting the plugins directory&quot;">​</a></h2><p>Getting a replacement jar into <code>/app/plugins</code> without rebuilding the image is a Docker volume-mounting question, not a TORCH one, but it has two sharp edges worth calling out:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  torch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ghcr.io/medizininformatik-initiative/torch:latest</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    volumes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">torch-data-store:/app/output</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">./plugins:/app/plugins</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # replaces the image&#39;s plugins directory entirely</span></span></code></pre></div><ul><li><strong>Bind mounts shadow, they don&#39;t merge.</strong> A bind mount like <code>./plugins</code> above replaces the image&#39;s <code>/app/plugins</code> completely — the <code>torch-consent-mii.jar</code> baked into the image is no longer visible to the container. <code>./plugins</code> on the host must therefore contain every jar you want loaded: your replacement <code>ConsentEvaluator</code> jar, plus <code>torch-consent-mii.jar</code> itself if you&#39;re using <code>@ConditionalOnMissingBean</code> and want it available as a fallback. A named volume behaves differently the first time it&#39;s used — Docker pre-populates it from the image&#39;s <code>/app/plugins</code>, so the MII jar stays present automatically — but a reused volume behaves like a bind mount, with none of that pre-population.</li><li><strong>Permissions travel with the mount, not the image.</strong> Files must be readable by UID <code>1001</code>, the non-root user TORCH runs as — the image&#39;s own <code>chown</code> to that user only applies to files baked into the image, not to anything mounted in from outside. An unreadable plugins directory looks the same as an empty one: <code>NoSuchBeanDefinitionException</code> for <code>ConsentEvaluator</code> at startup.</li></ul>`,13)])])}const m=t(a,[["render",s]]);export{u as __pageData,m as default};
